import React, { useState } from 'react';
import type { ControlPanelState, Framework, AppMode, Depth, Speed, Creativity } from '../types';
import { FRAMEWORKS } from '../constants';
import { 
  CogIcon, 
  WebIcon, 
  ImageIcon, 
  CheckCircleIcon, 
  BrainCircuitIcon, 
  WandSparklesIcon, 
  SaveIcon, 
  FolderOpenIcon, 
  TrashIcon 
} from './ui/icons';

interface ControlPanelProps {
  state: ControlPanelState;
  setState: React.Dispatch<React.SetStateAction<ControlPanelState>>;
  problem: string;
  setProblem: React.Dispatch<React.SetStateAction<string>>;
  onRun: () => void;
  onSave: () => void;
  onLoad: () => void;
  isLoading: boolean;
  isApiKeyMissing: boolean;
  mode: AppMode;
  setMode: React.Dispatch<React.SetStateAction<AppMode>>;
}

const ToggleButton: React.FC<{
  label: string;
  icon: React.ReactNode;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
  title?: string;
}> = ({ label, icon, isActive, onClick, disabled = false, title }) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    title={title}
    className={`flex items-center space-x-2 w-full p-2 rounded-md text-sm transition-colors ${
      isActive ? 'bg-accent-500 text-white shadow-lg shadow-accent-500/20' : 'bg-gray-800 border border-gray-700 hover:bg-gray-700'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

const TabButton: React.FC<{
  children: React.ReactNode;
  active: boolean;
  onClick: () => void;
}> = ({ children, active, onClick }) => (
  <button
    onClick={onClick}
    className={`px-4 py-3 text-xs font-bold uppercase tracking-widest rounded-t-md transition-all focus:outline-none w-1/2 border-b-2 ${
      active
        ? 'bg-gray-800 text-accent-400 border-accent-400'
        : 'text-gray-500 border-transparent hover:text-gray-300 hover:bg-gray-800/50'
    }`}
  >
    {children}
  </button>
);

const SegmentedControl: React.FC<{
  label: string;
  options: string[];
  value: string;
  onChange: (value: any) => void;
  disabled: boolean;
}> = ({ label, options, value, onChange, disabled }) => (
  <div className="space-y-2">
    <label className="block text-[10px] font-bold text-gray-500 uppercase tracking-tighter">{label}</label>
    <div className="flex bg-gray-900 p-1 rounded-lg border border-gray-800">
      {options.map((opt) => (
        <button
          key={opt}
          disabled={disabled}
          onClick={() => onChange(opt)}
          className={`flex-1 py-1.5 text-xs font-medium rounded-md transition-all ${
            value === opt
              ? 'bg-gray-700 text-white shadow-sm'
              : 'text-gray-500 hover:text-gray-300'
          } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          {opt}
        </button>
      ))}
    </div>
  </div>
);

export const ControlPanel: React.FC<ControlPanelProps> = ({
  state,
  setState,
  problem,
  setProblem,
  onRun,
  onSave,
  onLoad,
  isLoading,
  isApiKeyMissing,
  mode,
  setMode,
}) => {
  const [showAdmin, setShowAdmin] = useState(false);

  const updateState = (updates: Partial<ControlPanelState>) => {
    setState((prev) => ({ ...prev, ...updates }));
  };

  const selectedFrameworkData = FRAMEWORKS.find(f => f.name === state.framework);

  return (
    <aside className="w-full md:w-96 bg-gray-900 border-r border-gray-800 flex flex-col h-full shrink-0 shadow-2xl z-20">
      <div className="p-6 border-b border-gray-800 bg-gray-900/50">
        <div className="flex items-center space-x-3 mb-1">
          <BrainCircuitIcon className="w-8 h-8 text-accent-400" />
          <h1 className="text-xl font-black tracking-tighter text-white uppercase italic">System Blueprint</h1>
        </div>
        <p className="text-[10px] text-gray-500 font-mono leading-none tracking-tight">ENGINEERING COMPLEX RESOLUTIONS</p>
      </div>

      <div className="flex border-b border-gray-800">
        <TabButton active={mode === 'reasoning'} onClick={() => setMode('reasoning')}>Control Panel</TabButton>
        <TabButton active={mode === 'facts'} onClick={() => setMode('facts')}>Fact Matrix</TabButton>
      </div>

      <div className="flex-grow overflow-y-auto p-6 space-y-8 custom-scrollbar">
        {/* Input Area */}
        <div className="space-y-3">
          <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">
            {mode === 'reasoning' ? 'Core Objective / Problem' : 'Input Fact Set'}
          </label>
          <textarea
            value={problem}
            onChange={(e) => setProblem(e.target.value)}
            placeholder={mode === 'reasoning' ? "State the problem you need to solve..." : "Enter facts one by one..."}
            className="w-full h-32 bg-gray-800 border border-gray-700 rounded-lg p-3 text-sm text-gray-200 focus:ring-2 focus:ring-accent-500 focus:border-transparent outline-none resize-none transition-all placeholder:text-gray-600 font-mono"
          />
        </div>

        {mode === 'reasoning' && (
          <>
            {/* Logic Settings */}
            <div className="grid grid-cols-1 gap-4">
              <SegmentedControl
                label="Computing Depth"
                options={['Lite', 'Pro']}
                value={state.depth}
                onChange={(v) => updateState({ depth: v })}
                disabled={isLoading}
              />
              <SegmentedControl
                label="Process Speed"
                options={['Fast', 'Balanced', 'Careful']}
                value={state.speed}
                onChange={(v) => updateState({ speed: v })}
                disabled={isLoading}
              />
              <SegmentedControl
                label="Entropy / Creativity"
                options={['Low', 'Medium', 'High']}
                value={state.creativity}
                onChange={(v) => updateState({ creativity: v })}
                disabled={isLoading}
              />
            </div>

            {/* Framework Selector */}
            <div className="space-y-3">
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">Cognitive Framework</label>
              <select
                value={state.framework}
                onChange={(e) => updateState({ framework: e.target.value as Framework })}
                className="w-full bg-gray-800 border border-gray-700 rounded-lg p-2.5 text-sm text-gray-200 focus:ring-2 focus:ring-accent-500 outline-none cursor-pointer"
              >
                {FRAMEWORKS.map((f) => (
                  <option key={f.name} value={f.name}>{f.name}</option>
                ))}
              </select>
              {selectedFrameworkData && (
                <p className="text-[11px] text-gray-500 leading-relaxed italic px-1">
                  {selectedFrameworkData.description}
                </p>
              )}
            </div>

            {/* Functional Toggles */}
            <div className="space-y-3">
              <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest">Enhanced Modules</label>
              <div className="grid grid-cols-2 gap-2">
                <ToggleButton
                  label="Web Link"
                  icon={<WebIcon className="w-4 h-4" />}
                  isActive={state.web}
                  onClick={() => updateState({ web: !state.web })}
                />
                <ToggleButton
                  label="Visualizer"
                  icon={<ImageIcon className="w-4 h-4" />}
                  isActive={state.images}
                  onClick={() => updateState({ images: !state.images })}
                />
                <ToggleButton
                  label="Meta-Fix"
                  icon={<CogIcon className="w-4 h-4" />}
                  isActive={state.metaFix}
                  onClick={() => updateState({ metaFix: !state.metaFix })}
                  title="Enables self-critique module"
                />
                <ToggleButton
                  label="Reflection"
                  icon={<CheckCircleIcon className="w-4 h-4" />}
                  isActive={state.selfReflection}
                  onClick={() => updateState({ selfReflection: !state.selfReflection })}
                  title="Enables confidence score rating"
                />
              </div>
            </div>
          </>
        )}

        {/* Action Buttons */}
        <div className="pt-4 space-y-3 border-t border-gray-800">
          <button
            onClick={onRun}
            disabled={isLoading || isApiKeyMissing}
            className={`w-full py-4 rounded-xl font-black text-sm uppercase tracking-[0.2em] transition-all flex items-center justify-center space-x-2 ${
              isLoading 
                ? 'bg-gray-800 text-gray-600 cursor-not-allowed' 
                : 'bg-accent-500 hover:bg-accent-400 text-gray-900 shadow-xl shadow-accent-500/20 active:scale-95'
            }`}
          >
            {isLoading ? (
              <>
                <div className="animate-spin h-4 w-4 border-2 border-gray-400 border-t-transparent rounded-full" />
                <span>Processing...</span>
              </>
            ) : (
              <>
                <WandSparklesIcon className="w-5 h-5" />
                <span>{mode === 'reasoning' ? 'Execute Blueprint' : 'Analyze Matrix'}</span>
              </>
            )}
          </button>

          <div className="grid grid-cols-2 gap-2">
            <button
              onClick={onSave}
              className="flex items-center justify-center space-x-2 py-2.5 bg-gray-800 border border-gray-700 hover:bg-gray-700 rounded-lg text-xs font-bold text-gray-300 transition-all"
            >
              <SaveIcon className="w-4 h-4" />
              <span>Save State</span>
            </button>
            <button
              onClick={onLoad}
              className="flex items-center justify-center space-x-2 py-2.5 bg-gray-800 border border-gray-700 hover:bg-gray-700 rounded-lg text-xs font-bold text-gray-300 transition-all"
            >
              <FolderOpenIcon className="w-4 h-4" />
              <span>History</span>
            </button>
          </div>
        </div>

        {/* Admin Settings Link */}
        <div className="pt-6 border-t border-gray-800">
           <button 
             onClick={() => setShowAdmin(!showAdmin)}
             className="text-[10px] text-gray-600 hover:text-gray-400 uppercase font-bold tracking-widest flex items-center"
           >
             <CogIcon className="w-3 h-3 mr-1" />
             {showAdmin ? 'Hide Admin Controls' : 'Admin Settings'}
           </button>

           {showAdmin && (
             <div className="mt-4 p-4 bg-gray-950 rounded-lg border border-gray-800 space-y-4 animate-in fade-in slide-in-from-top-2">
                <div className="space-y-2">
                   <label className="block text-[10px] font-bold text-gray-500 uppercase">PayPal.me Link</label>
                   <input 
                     type="text"
                     placeholder="e.g. paypal.me/yourname"
                     value={state.paypalLink}
                     onChange={(e) => updateState({ paypalLink: e.target.value })}
                     className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-xs text-accent-300 font-mono outline-none focus:border-accent-500"
                   />
                   <p className="text-[9px] text-gray-600 italic">This link is used by the Support Agent for retainer payments.</p>
                </div>
             </div>
           )}
        </div>
      </div>
    </aside>
  );
};

import type { Framework, ControlPanelState } from './types';

export const SYSTEM_PROMPT = `You are an advanced reasoning engine designed to solve complex challenges through structural architecture and tiered logic.
You must structure your response in Markdown format with these five specific sections:

1.  **Clear, Direct Answer:** Provide a definitive, immediate, and concise resolution to the user's core question.
2.  **System Blueprint:** Provide a high-level architectural overview. Map out the solution's core components, their interdependencies, and the structural flow of the resolution.
3.  **Reasoning:** A rigorous, step-by-step breakdown of the logic used. This is the "compute" phase.
4.  **Alternatives:** Contrast the primary solution against two distinct alternative pathways, highlighting trade-offs (Speed vs. Stability vs. Cost).
5.  **Action Plan:** A modular, actionable roadmap with clear "Step 0" and "Next Actions".

Adhere strictly to this 5-part structure. Use clear headings and professional formatting.`;

export const FACT_ORGANIZER_PROMPT = `SYSTEM INSTRUCTION:
You are the Fact Organizer + Gap-Detection Engine.
Your purpose is to take provided data points, arrange them into an organized matrix, and automatically run a gap-detection analysis to highlight missing info or logical inconsistencies.

OUTPUT FORMAT:
[1] Organized Fact Map (Categorized)
[2] Gap & Conflict Summary (Detection)
[3] Suggested Data Requirements
[4] Refined Problem Statement`;

export const META_FIX_PROMPT_INSTRUCTION = `Add a "Meta-Fix" section critiquing the solution's own logical architecture and identifying one failure point. Format: **Meta-Fix:** [Critique].`;

export const SELF_REFLECTION_PROMPT_INSTRUCTION = `Add a "Self-Reflection" section with a confidence score (1-10) and structural justification. Format: **Self-Reflection:** **Confidence Score:** [score]/10 **Justification:** [text].`;

export const IMAGE_PROMPT_INSTRUCTION = `Include an <IMAGE_PROMPT>...</IMAGE_PROMPT> tag for a technical blueprint visualization of the solution.`;

interface FrameworkDefinition {
  name: Framework;
  description: string;
  primaryDrivers: string[];
  apply: (prompt: string, state: ControlPanelState) => string;
}

const createSimpleFramework = (name: Framework, description: string, drivers: string[], instruction?: string): FrameworkDefinition => ({
  name,
  description,
  primaryDrivers: drivers,
  apply: (prompt) => prompt + `\n\nFRAMEWORK INSTRUCTION (${name}):\n${instruction || `Apply the principles of ${name} to solve this problem.`}`
});

export const FRAMEWORKS: FrameworkDefinition[] = [
  {
    name: 'None',
    description: 'Standard AI reasoning.',
    primaryDrivers: ['Standard LLM Reasoning'],
    apply: (prompt) => prompt,
  },
  {
    name: 'System Blueprint',
    description: 'Focuses on the structural architecture and modular layout of the resolution.',
    primaryDrivers: ['Modular Logic', 'Flow Mapping', 'Architecture'],
    apply: (prompt) => prompt + `\n\nFRAMEWORK INSTRUCTION (System Blueprint):\nDeconstruct the problem into a system of modules. Explicitly map inputs, internal logic gates, and outputs. Treat the solution as a designed machine.`
  },
  {
    name: 'Cognitive Lenses',
    description: 'Analyzes the problem through Average (Symptoms), Intelligent (Systems), and Genius (First Principles) tiers.',
    primaryDrivers: ['Tiered Perspective', 'Paradigm Shifts', 'Strategic Depth'],
    apply: (prompt) => prompt + `\n\nFRAMEWORK INSTRUCTION (Cognitive Lenses):\nEvaluate this through three tiers of cognitive intensity:\n\n1. The Average Approach: Focus on symptoms, standard best practices, and consensus-driven relief.\n2. The Intelligent Approach: Focus on root cause analysis, optimization, and second-order systems thinking.\n3. The Genius Approach: Focus on First Principles, Inversion (how to guarantee failure), and paradigm shifts that make the original problem obsolete.`
  },
  {
    name: 'Causal Spine',
    description: 'Identifies the central chain of cause and effect.',
    primaryDrivers: ['Root Cause', 'Direct Impact'],
    apply: (prompt) => prompt + `\n\nFRAMEWORK INSTRUCTION (Causal Spine): Isolate the core causal chain. Ignore noise. Focus on the spine of the issue.`
  },
  {
    name: 'First Principles Thinking',
    description: 'Deconstructs to basic truths.',
    primaryDrivers: ['Deconstruction', 'Foundational Truths'],
    apply: (prompt) => prompt + `\n\nFRAMEWORK INSTRUCTION (First Principles): Break the problem into its fundamental, immutable truths. Rebuild the solution from the ground up without using analogies.`
  },
  createSimpleFramework('Systems Thinking', 'Analyzes interacting components.', ['Interconnections', 'Feedback Loops']),
  createSimpleFramework('Inversion', 'Thinking backwards to avoid failure.', ['Avoidance', 'Perspective']),
  createSimpleFramework('Antifragility', 'Building systems that thrive on disorder.', ['Stress Tolerance', 'Gain from Chaos']),
  createSimpleFramework('Second-Order Thinking', 'Analyzing future consequences.', ['Cascading Effects', 'Timeline Analysis']),
  createSimpleFramework('Red Teaming', 'Rigorous adversarial challenge.', ['Vulnerability Testing', 'Stress Test']),
  createSimpleFramework('MECE', 'Mutually Exclusive, Collectively Exhaustive structure.', ['Completeness', 'Structure']),
  createSimpleFramework('TRIZ', 'Theory of Inventive Problem Solving.', ['Innovation', 'Contradiction']),
  createSimpleFramework('Bayesian Inference', 'Updating probabilities based on new evidence.', ['Probability', 'Logic']),
  createSimpleFramework('Game Theory', 'Strategic interaction analysis.', ['Nash Equilibrium', 'Payoffs']),
  createSimpleFramework('Occam\'s Razor', 'Principle of simplicity.', ['Parsimony', 'Logic']),
];

