import React, { useState, useCallback, useEffect, useRef } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { OutputDisplay } from './components/OutputDisplay';
import { LoadSessionModal } from './components/LoadSessionModal';
import { SupportAgent } from './components/SupportAgent';
import type { OutputDisplayHandle } from './components/OutputDisplay';
import type { ControlPanelState, ResultState, SavedSession, AppMode } from './types';
import { runReasoning, runFactAnalysis } from './services/geminiService';

const App: React.FC = () => {
  const [problem, setProblem] = useState('');
  const [mode, setMode] = useState<AppMode>('reasoning');
  const [controlState, setControlState] = useState<ControlPanelState>({
    depth: 'Lite',
    speed: 'Fast',
    creativity: 'Low',
    web: true,
    images: false,
    metaFix: true,
    selfReflection: false,
    framework: 'System Blueprint',
    paypalLink: '',
  });

  const [result, setResult] = useState<ResultState | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [apiKeyError, setApiKeyError] = useState<string | null>(null);
  const [savedSessions, setSavedSessions] = useState<SavedSession[]>([]);
  const [isLoadModalOpen, setIsLoadModalOpen] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState<'none' | 'pending'>('none');
  const outputDisplayRef = useRef<OutputDisplayHandle>(null);

  useEffect(() => {
    if (!process.env.API_KEY) {
      setApiKeyError("API key not found. Please check your environment variables.");
    }
    try {
      const storedSessions = localStorage.getItem('reasoning_sessions');
      if (storedSessions) {
        setSavedSessions(JSON.parse(storedSessions));
      }

      const storedPaypal = localStorage.getItem('paypal_link');
      if (storedPaypal) {
        setControlState(prev => ({ ...prev, paypalLink: storedPaypal }));
      }
    } catch (e) {
      console.error("Failed to load persistence layer", e);
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('paypal_link', controlState.paypalLink);
  }, [controlState.paypalLink]);

  const handleSaveSession = useCallback(() => {
    if (!problem.trim()) {
        alert("Enter an objective before saving.");
        return;
    }

    const sessionName = problem.substring(0, 50) + (problem.length > 50 ? '...' : '');

    const newSession: SavedSession = {
      id: Date.now(),
      name: sessionName,
      timestamp: new Date().toISOString(),
      problem,
      controlState,
      result,
      mode,
    };

    const updatedSessions = [newSession, ...savedSessions];
    setSavedSessions(updatedSessions);
    localStorage.setItem('reasoning_sessions', JSON.stringify(updatedSessions));
  }, [problem, controlState, result, savedSessions, mode]);

  const handleLoadSession = useCallback((session: SavedSession) => {
      setProblem(session.problem);
      setControlState(session.controlState);
      setResult(session.result);
      setMode(session.mode ?? 'reasoning');
      setIsLoadModalOpen(false);
  }, []);

  const handleDeleteSession = useCallback((sessionId: number) => {
      const updatedSessions = savedSessions.filter(s => s.id !== sessionId);
      setSavedSessions(updatedSessions);
      localStorage.setItem('reasoning_sessions', JSON.stringify(updatedSessions));
  }, [savedSessions]);

  const handleRun = useCallback(async () => {
    if (apiKeyError) return;
    const input = problem.trim();
    if (!input) {
      setError(mode === 'reasoning' ? 'Please enter a problem statement.' : 'Please enter facts.');
      return;
    }
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      let response;
      if (mode === 'reasoning') {
          response = await runReasoning(input, controlState);
      } else {
          response = await runFactAnalysis(input);
      }
      setResult(response);
    } catch (e) {
      console.error(e);
      setError(e instanceof Error ? e.message : 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  }, [problem, controlState, apiKeyError, mode]);

  const handlePay = useCallback(() => {
    const link = controlState.paypalLink.trim();
    if (!link) {
      alert("Configure a PayPal.me link in Admin Settings.");
      return;
    }
    const cleanedHandle = link.replace(/^https?:\/\/(www\.)?paypal\.me\//, '');
    const payUrl = `https://www.paypal.me/${cleanedHandle}/120`;
    window.open(payUrl, '_blank');
    setPaymentStatus('pending');
  }, [controlState.paypalLink]);

  return (
    <div className="flex flex-col md:flex-row min-h-screen md:h-screen md:overflow-hidden font-sans">
      <ControlPanel
        state={controlState}
        setState={setControlState}
        problem={problem}
        setProblem={setProblem}
        onRun={handleRun}
        onSave={handleSaveSession}
        onLoad={() => setIsLoadModalOpen(true)}
        isLoading={loading}
        isApiKeyMissing={!!apiKeyError}
        mode={mode}
        setMode={setMode}
      />

      <main className="flex-grow flex flex-col md:h-full md:overflow-hidden bg-gray-900 relative">
        {apiKeyError && (
          <div className="bg-red-900/80 border-b border-red-500 text-red-200 px-4 py-2 text-center text-sm">
            {apiKeyError}
          </div>
        )}

        <div className="flex-grow md:overflow-y-auto p-4 md:p-8">
            <SupportAgent status={paymentStatus} onPay={handlePay} />
            <OutputDisplay 
                ref={outputDisplayRef} 
                result={result} 
                isLoading={loading} 
                error={error} 
            />
        </div>

        {result && !loading && !error && (
            <div className="fixed md:absolute bottom-6 right-8 flex space-x-2 z-10">
                <button 
                    onClick={() => outputDisplayRef.current?.exportToPNG()}
                    className="bg-gray-700 hover:bg-gray-600 text-white text-xs px-3 py-2 rounded shadow transition-all"
                >
                    Export PNG
                </button>
                 <button 
                    onClick={() => outputDisplayRef.current?.exportToPDF()}
                    className="bg-gray-700 hover:bg-gray-600 text-white text-xs px-3 py-2 rounded shadow transition-all"
                >
                    Export PDF
                </button>
            </div>
        )}
      </main>

      <LoadSessionModal
        isOpen={isLoadModalOpen}
        sessions={savedSessions}
        onClose={() => setIsLoadModalOpen(false)}
        onLoad={handleLoadSession}
        onDelete={handleDeleteSession}
      />
    </div>
  );
};

export default App;

