import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import type { ControlPanelState, ResultState, Source } from '../types';
import { FRAMEWORKS, SYSTEM_PROMPT, META_FIX_PROMPT_INSTRUCTION, SELF_REFLECTION_PROMPT_INSTRUCTION, IMAGE_PROMPT_INSTRUCTION, FACT_ORGANIZER_PROMPT } from '../constants';

const createClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API key is missing in environment.");
  }
  return new GoogleGenAI({ apiKey });
};

const extractImagePrompt = (text: string): { cleanedText: string; prompt?: string } => {
  const match = text.match(/<IMAGE_PROMPT>(.*?)<\/IMAGE_PROMPT>/s);
  if (match && match[1]) {
    const cleanedText = text.replace(/<IMAGE_PROMPT>.*?<\/IMAGE_PROMPT>/s, '').trim();
    return { cleanedText, prompt: match[1].trim() };
  }
  return { cleanedText: text, prompt: undefined };
};

export const runFactAnalysis = async (facts: string): Promise<ResultState> => {
  const ai = createClient();
  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `${FACT_ORGANIZER_PROMPT}\n\nINPUT DATA:\n${facts}`,
  });
  return { markdown: response.text || '', sources: [] };
};

export const runReasoning = async (problem: string, state: ControlPanelState): Promise<ResultState> => {
  const ai = createClient();
  const modelName = state.depth === 'Pro' ? 'gemini-3-pro-preview' : 'gemini-3-flash-preview';

  let fullPrompt = `${SYSTEM_PROMPT}\n\nOBJECTIVE:\n${problem}\n\n`;

  const framework = FRAMEWORKS.find(f => f.name === state.framework);
  if (framework) fullPrompt = framework.apply(fullPrompt, state);

  if (state.metaFix) fullPrompt += `\n${META_FIX_PROMPT_INSTRUCTION}`;
  if (state.images) fullPrompt += `\n${IMAGE_PROMPT_INSTRUCTION}`;
  if (state.selfReflection) fullPrompt += `\n${SELF_REFLECTION_PROMPT_INSTRUCTION}`;

  const temperatureMap = { 'Low': 0.1, 'Medium': 0.5, 'High': 0.9 };
  const speedMap = { 'Fast': 0, 'Balanced': 12288, 'Careful': 24576 };

  const tools: any[] = [];
  if (state.web) tools.push({ googleSearch: {} });

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: modelName,
    contents: fullPrompt,
    config: {
      temperature: temperatureMap[state.creativity],
      ...(tools.length > 0 && { tools }),
      ...(modelName.includes('flash') && { thinkingConfig: { thinkingBudget: speedMap[state.speed] } })
    }
  });

  let rawMarkdown = response.text || '';
  const { cleanedText, prompt: imagePrompt } = extractImagePrompt(rawMarkdown);

  const sources: Source[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks
    ?.map((c: any) => c.web ? { uri: c.web.uri, title: c.web.title } : null)
    .filter(Boolean) ?? [];

  let imageUrl: string | undefined;
  if (state.images && imagePrompt) {
    try {
      const imgRes = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: `High quality blueprint style illustration of: ${imagePrompt}` }] }
      });
      const imgPart = imgRes.candidates?.[0]?.content?.parts.find(p => p.inlineData);
      if (imgPart?.inlineData) imageUrl = `data:image/png;base64,${imgPart.inlineData.data}`;
    } catch (e) {
      console.error("Visualizer failed", e);
    }
  }

  return { markdown: cleanedText, sources, imageUrl, imagePrompt };
};

import React, { useState } from 'react';
import type { ControlPanelState, Framework, AppMode } from '../types';
import { FRAMEWORKS } from '../constants';
import { 
  CogIcon, 
  WebIcon, 
  ImageIcon, 
  CheckCircleIcon, 
  BrainCircuitIcon, 
  WandSparklesIcon, 
  SaveIcon, 
  FolderOpenIcon, 
} from './ui/icons';

interface ControlPanelProps {
  state: ControlPanelState;
  setState: React.Dispatch<React.SetStateAction<ControlPanelState>>;
  problem: string;
  setProblem: React.Dispatch<React.SetStateAction<string>>;
  onRun: () => void;
  onSave: () => void;
  onLoad: () => void;
  isLoading: boolean;
  isApiKeyMissing: boolean;
  mode: AppMode;
  setMode: React.Dispatch<React.SetStateAction<AppMode>>;
}

const ToggleButton: React.FC<{
  label: string;
  icon: React.ReactNode;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
}> = ({ label, icon, isActive, onClick, disabled = false }) => (
  <button
    type="button"
    onClick={onClick}
    disabled={disabled}
    className={`flex items-center space-x-2 w-full p-2.5 rounded-lg text-sm transition-all duration-200 ${
      isActive ? 'bg-accent-500 text-gray-950 shadow-lg shadow-accent-500/20 font-bold' : 'bg-gray-800 border border-gray-700 hover:bg-gray-750 text-gray-400'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span>{label}</span>
  </button>
);

const TabButton: React.FC<{
  children: React.ReactNode;
  active: boolean;
  onClick: () => void;
}> = ({ children, active, onClick }) => (
  <button
    onClick={onClick}
    className={`px-4 py-3.5 text-[10px] font-black uppercase tracking-widest transition-all focus:outline-none w-1/2 border-b-2 ${
      active
        ? 'bg-gray-800 text-accent-400 border-accent-400'
        : 'text-gray-500 border-transparent hover:text-gray-300 hover:bg-gray-800/30'
    }`}
  >
    {children}
  </button>
);

const SegmentedControl: React.FC<{
  label: string;
  options: string[];
  value: string;
  onChange: (value: any) => void;
  disabled: boolean;
}> = ({ label, options, value, onChange, disabled }) => (
  <div className="space-y-1.5">
    <label className="block text-[10px] font-black text-gray-500 uppercase tracking-widest">{label}</label>
    <div className="flex bg-gray-950 p-1.5 rounded-lg border border-gray-800 gap-1">
      {options.map((opt) => (
        <button
          key={opt}
          disabled={disabled}
          onClick={() => onChange(opt)}
          className={`flex-1 py-1.5 text-[10px] font-bold rounded-md transition-all ${
            value === opt
              ? 'bg-gray-800 text-white border border-gray-700 shadow-sm'
              : 'text-gray-600 hover:text-gray-400'
          } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          {opt}
        </button>
      ))}
    </div>
  </div>
);

export const ControlPanel: React.FC<ControlPanelProps> = ({
  state, setState, problem, setProblem, onRun, onSave, onLoad, isLoading, isApiKeyMissing, mode, setMode
}) => {
  const [showAdmin, setShowAdmin] = useState(false);
  const updateState = (updates: Partial<ControlPanelState>) => setState(prev => ({ ...prev, ...updates }));
  const selectedFrameworkData = FRAMEWORKS.find(f => f.name === state.framework);

  return (
    <aside className="w-full md:w-85 bg-gray-900 border-r border-gray-800 flex flex-col h-full shrink-0 shadow-2xl">
      <div className="p-6 border-b border-gray-800 bg-gray-900">
        <div className="flex items-center space-x-3 mb-1">
          <BrainCircuitIcon className="w-8 h-8 text-accent-400" />
          <h1 className="text-xl font-black tracking-tighter text-white uppercase italic">System Blueprint</h1>
        </div>
      </div>

      <div className="flex border-b border-gray-800">
        <TabButton active={mode === 'reasoning'} onClick={() => setMode('reasoning')}>Control</TabButton>
        <TabButton active={mode === 'facts'} onClick={() => setMode('facts')}>Matrix</TabButton>
      </div>

      <div className="flex-grow overflow-y-auto p-6 space-y-7 custom-scrollbar bg-gray-900">
        <div className="space-y-2.5">
          <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest">
            {mode === 'reasoning' ? 'Core Objective' : 'Data Entry'}
          </label>
          <textarea
            value={problem}
            onChange={(e) => setProblem(e.target.value)}
            placeholder={mode === 'reasoning' ? "State the primary challenge..." : "List facts to analyze..."}
            className="w-full h-32 bg-gray-800 border border-gray-700 rounded-xl p-4 text-xs text-gray-200 focus:ring-1 focus:ring-accent-500 outline-none resize-none transition-all font-mono leading-relaxed placeholder:text-gray-600"
          />
        </div>

        {mode === 'reasoning' && (
          <>
            <div className="grid grid-cols-1 gap-4">
              <SegmentedControl label="Depth" options={['Lite', 'Pro']} value={state.depth} onChange={(v) => updateState({ depth: v })} disabled={isLoading} />
              <SegmentedControl label="Logic Speed" options={['Fast', 'Balanced', 'Careful']} value={state.speed} onChange={(v) => updateState({ speed: v })} disabled={isLoading} />
              <SegmentedControl label="Entropy" options={['Low', 'Medium', 'High']} value={state.creativity} onChange={(v) => updateState({ creativity: v })} disabled={isLoading} />
            </div>

            <div className="space-y-2.5">
              <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest">Cognitive Framework</label>
              <select
                value={state.framework}
                onChange={(e) => updateState({ framework: e.target.value as Framework })}
                className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-xs text-gray-200 focus:ring-1 focus:ring-accent-500 outline-none appearance-none"
              >
                {FRAMEWORKS.map((f) => <option key={f.name} value={f.name}>{f.name}</option>)}
              </select>
              {selectedFrameworkData && (
                <p className="text-[10px] text-gray-500 italic px-1 leading-normal">{selectedFrameworkData.description}</p>
              )}
            </div>

            <div className="space-y-2.5">
              <label className="block text-[11px] font-black text-gray-500 uppercase tracking-widest">Module Overlays</label>
              <div className="grid grid-cols-2 gap-2.5">
                <ToggleButton label="Web" icon={<WebIcon className="w-4 h-4" />} isActive={state.web} onClick={() => updateState({ web: !state.web })} />
                <ToggleButton label="Visualizer" icon={<ImageIcon className="w-4 h-4" />} isActive={state.images} onClick={() => updateState({ images: !state.images })} />
                <ToggleButton label="Meta-Fix" icon={<CogIcon className="w-4 h-4" />} isActive={state.metaFix} onClick={() => updateState({ metaFix: !state.metaFix })} />
                <ToggleButton label="Reflection" icon={<CheckCircleIcon className="w-4 h-4" />} isActive={state.selfReflection} onClick={() => updateState({ selfReflection: !state.selfReflection })} />
              </div>
            </div>
          </>
        )}

        <div className="pt-6 space-y-4 border-t border-gray-800">
          <button
            onClick={onRun}
            disabled={isLoading || isApiKeyMissing}
            className={`w-full py-4 rounded-xl font-black text-xs uppercase tracking-[0.15em] transition-all flex items-center justify-center space-x-2 ${
              isLoading ? 'bg-gray-800 text-gray-600' : 'bg-accent-500 hover:bg-accent-400 text-gray-950 shadow-xl shadow-accent-500/10 active:scale-[0.98]'
            }`}
          >
            {isLoading ? <div className="animate-spin h-4 w-4 border-2 border-gray-500 border-t-transparent rounded-full" /> : <><WandSparklesIcon className="w-5 h-5" /><span>{mode === 'reasoning' ? 'Execute Blueprint' : 'Analyze Matrix'}</span></>}
          </button>

          <div className="grid grid-cols-2 gap-2.5">
            <button onClick={onSave} className="flex items-center justify-center space-x-2 py-3 bg-gray-800 border border-gray-700 rounded-lg text-[10px] font-black text-gray-300 uppercase tracking-wider hover:bg-gray-750 transition-colors"><SaveIcon className="w-4 h-4" /><span>Save</span></button>
            <button onClick={onLoad} className="flex items-center justify-center space-x-2 py-3 bg-gray-800 border border-gray-700 rounded-lg text-[10px] font-black text-gray-300 uppercase tracking-wider hover:bg-gray-750 transition-colors"><FolderOpenIcon className="w-4 h-4" /><span>History</span></button>
          </div>
        </div>

        <div className="pt-6 border-t border-gray-800">
          <button onClick={() => setShowAdmin(!showAdmin)} className="text-[10px] text-gray-600 hover:text-gray-400 uppercase font-black tracking-widest flex items-center transition-colors">
            <CogIcon className="w-3 h-3 mr-1.5" />
            Admin Settings
          </button>
          {showAdmin && (
            <div className="mt-4 p-4 bg-gray-950 rounded-xl border border-gray-800 space-y-4">
              <div className="space-y-1.5">
                <label className="block text-[9px] font-black text-gray-500 uppercase tracking-widest">PayPal Link</label>
                <input 
                  type="text" placeholder="paypal.me/handle" 
                  value={state.paypalLink} onChange={(e) => updateState({ paypalLink: e.target.value })}
                  className="w-full bg-gray-900 border border-gray-700 rounded-lg p-2.5 text-[10px] text-accent-300 font-mono outline-none focus:border-accent-500"
                />
              </div>
            </div>
          )}
        </div>
      </div>
    </aside>
  );
};

